(function () {
  'use strict';

  // Wing bezier in wing.svg coordinate space.
  // The #wing-right / #wing-left group transforms handle scaling + placement.
  const P0  = [60,  280];
  const P3b = [640, 190];
  const P1b = [100,  40];
  const P2b = [480,  20];

  const PERIOD  = 1.6;
  const AMP_P1y = 72;
  const AMP_P2y = 95;
  const AMP_P3y = 55;
  const LAG_P2  = 0.15;
  const LAG_P3  = 0.32;

  function B(t, p1, p2, p3) {
    const mt = 1 - t;
    return [
      mt*mt*mt*P0[0] + 3*mt*mt*t*p1[0] + 3*mt*t*t*p2[0] + t*t*t*p3[0],
      mt*mt*mt*P0[1] + 3*mt*mt*t*p1[1] + 3*mt*t*t*p2[1] + t*t*t*p3[1]
    ];
  }

  function Bprime(t, p1, p2, p3) {
    const mt = 1 - t;
    return [
      3*(mt*mt*(p1[0]-P0[0]) + 2*mt*t*(p2[0]-p1[0]) + t*t*(p3[0]-p2[0])),
      3*(mt*mt*(p1[1]-P0[1]) + 2*mt*t*(p2[1]-p1[1]) + t*t*(p3[1]-p2[1]))
    ];
  }

  function inwardNormal(t, p1, p2, p3) {
    const [dx, dy] = Bprime(t, p1, p2, p3);
    const len = Math.hypot(dx, dy);
    return [-dy / len, dx / len];
  }

  const LAYER1_T = [0.05,0.0923,0.1345,0.176,0.2162,0.2548,0.2916,0.3267,0.36,
    0.3916,0.4218,0.4505,0.478,0.5042,0.5294,0.5536,0.5769,0.5993,0.6209,
    0.6417,0.6619,0.6814,0.7003,0.7186,0.7363,0.7535,0.7701,0.7863,0.802,
    0.8172,0.832,0.8463,0.8602,0.8737,0.8868,0.8995,0.9118,0.9237,0.9353,
    0.9465,0.9573,0.9678];

  const LAYER2_T = [0.0711,0.1135,0.1554,0.1963,0.2357,0.2734,0.3094,0.3436,
    0.376,0.4069,0.4363,0.4644,0.4913,0.517,0.5416,0.5654,0.5882,0.6102,
    0.6314,0.6519,0.6717,0.6909,0.7095,0.7275,0.745,0.7619,0.7783,0.7942,
    0.8097,0.8246,0.8392,0.8533,0.867,0.8803,0.8932,0.9057,0.9178,0.9296,
    0.9409,0.952,0.9626,0.973,0.983];

  const scaleAt         = t => Math.max(0.20, 1.0 - 0.74 * (t - 0.05) / 0.90);
  const FEATHER_LEN     = 207;
  const L2_OFFSET_FRAC  = 0.25;

  const SVG_NS = 'http://www.w3.org/2000/svg';
  function makeUses(containerId, tArr) {
    const g = document.getElementById(containerId);
    return tArr.map(t => {
      const el = document.createElementNS(SVG_NS, 'use');
      el.setAttribute('href', '#f');
      g.appendChild(el);
      return { el, t, s: scaleAt(t) };
    });
  }

  // Four layers: right and left wings share the same t-values and transform math.
  // The parent #wing-right / #wing-left groups handle mirroring — JS writes
  // wing-space transforms identically for both sides.
  const uses1R = makeUses('layer1R', LAYER1_T);
  const uses2R = makeUses('layer2R', LAYER2_T);
  const uses1L = makeUses('layer1L', LAYER1_T);
  const uses2L = makeUses('layer2L', LAYER2_T);

  function applyLayer1(uses, p1, p2, p3) {
    for (const { el, t, s } of uses) {
      const [x, y] = B(t, p1, p2, p3);
      el.setAttribute('transform',
        `translate(${x.toFixed(1)},${y.toFixed(1)}) rotate(180) scale(${s.toFixed(2)})`);
    }
  }

  function applyLayer2(uses, p1, p2, p3) {
    for (const { el, t, s } of uses) {
      const [x, y] = B(t, p1, p2, p3);
      const [nx, ny] = inwardNormal(t, p1, p2, p3);
      const off = L2_OFFSET_FRAC * FEATHER_LEN * s;
      el.setAttribute('transform',
        `translate(${(x + nx*off).toFixed(1)},${(y + ny*off).toFixed(1)}) rotate(180) scale(${s.toFixed(2)})`);
    }
  }

  function frame(ms) {
    const phase = (ms / 1000 / PERIOD) * Math.PI * 2;
    const p1 = [P1b[0], P1b[1] + AMP_P1y * Math.sin(phase)];
    const p2 = [P2b[0], P2b[1] + AMP_P2y * Math.sin(phase - LAG_P2)];
    const p3 = [P3b[0], P3b[1] + AMP_P3y * Math.sin(phase - LAG_P3)];

    applyLayer1(uses1R, p1, p2, p3);
    applyLayer2(uses2R, p1, p2, p3);
    applyLayer1(uses1L, p1, p2, p3);
    applyLayer2(uses2L, p1, p2, p3);

    requestAnimationFrame(frame);
  }

  requestAnimationFrame(frame);
})();

script:
(function () {
  'use strict';

  // Wing bezier control points (wing.svg coordinate space — transform on #wing-layer handles mapping)
  const P0  = [60,  280];
  const P3b = [640, 190];
  const P1b = [100,  40];
  const P2b = [480,  20];

  // Flap parameters
  const PERIOD  = 1.6;    // seconds per full cycle
  const AMP_P1y = 72;     // root control amplitude (px)
  const AMP_P2y = 95;     // mid control amplitude
  const AMP_P3y = 55;     // tip endpoint amplitude
  const LAG_P2  = 0.15;   // P2 lags P1 (rad)
  const LAG_P3  = 0.32;   // P3 lags P1 (rad)

  // Bezier evaluation
  function B(t, p1, p2, p3) {
    const mt = 1 - t;
    return [
      mt*mt*mt*P0[0] + 3*mt*mt*t*p1[0] + 3*mt*t*t*p2[0] + t*t*t*p3[0],
      mt*mt*mt*P0[1] + 3*mt*mt*t*p1[1] + 3*mt*t*t*p2[1] + t*t*t*p3[1]
    ];
  }

  function Bprime(t, p1, p2, p3) {
    const mt = 1 - t;
    return [
      3*(mt*mt*(p1[0]-P0[0]) + 2*mt*t*(p2[0]-p1[0]) + t*t*(p3[0]-p2[0])),
      3*(mt*mt*(p1[1]-P0[1]) + 2*mt*t*(p2[1]-p1[1]) + t*t*(p3[1]-p2[1]))
    ];
  }

  function inwardNormal(t, p1, p2, p3) {
    const [dx, dy] = Bprime(t, p1, p2, p3);
    const len = Math.hypot(dx, dy);
    return [-dy / len, dx / len];
  }

  // Feather t-value layout (Python arc-length walk, constant across all frames)
  const LAYER1_T = [0.05,0.0923,0.1345,0.176,0.2162,0.2548,0.2916,0.3267,0.36,
    0.3916,0.4218,0.4505,0.478,0.5042,0.5294,0.5536,0.5769,0.5993,0.6209,
    0.6417,0.6619,0.6814,0.7003,0.7186,0.7363,0.7535,0.7701,0.7863,0.802,
    0.8172,0.832,0.8463,0.8602,0.8737,0.8868,0.8995,0.9118,0.9237,0.9353,
    0.9465,0.9573,0.9678];

  const LAYER2_T = [0.0711,0.1135,0.1554,0.1963,0.2357,0.2734,0.3094,0.3436,
    0.376,0.4069,0.4363,0.4644,0.4913,0.517,0.5416,0.5654,0.5882,0.6102,
    0.6314,0.6519,0.6717,0.6909,0.7095,0.7275,0.745,0.7619,0.7783,0.7942,
    0.8097,0.8246,0.8392,0.8533,0.867,0.8803,0.8932,0.9057,0.9178,0.9296,
    0.9409,0.952,0.9626,0.973,0.983];

  const scaleAt   = t => Math.max(0.20, 1.0 - 0.74 * (t - 0.05) / 0.90);
  const FEATHER_LEN     = 207;
  const L2_OFFSET_FRAC  = 0.25;

  // Build <use> elements
  const SVG_NS = 'http://www.w3.org/2000/svg';
  function makeUses(containerId, tArr) {
    const g = document.getElementById(containerId);
    return tArr.map(t => {
      const el = document.createElementNS(SVG_NS, 'use');
      el.setAttribute('href', '#f');
      g.appendChild(el);
      return { el, t, s: scaleAt(t) };
    });
  }

  const uses1 = makeUses('layer1', LAYER1_T);
  const uses2 = makeUses('layer2', LAYER2_T);

  // Animation loop
  function frame(ms) {
    const phase = (ms / 1000 / PERIOD) * Math.PI * 2;
    const p1 = [P1b[0], P1b[1] + AMP_P1y * Math.sin(phase)];
    const p2 = [P2b[0], P2b[1] + AMP_P2y * Math.sin(phase - LAG_P2)];
    const p3 = [P3b[0], P3b[1] + AMP_P3y * Math.sin(phase - LAG_P3)];

    for (const { el, t, s } of uses1) {
      const [x, y] = B(t, p1, p2, p3);
      el.setAttribute('transform',
        `translate(${x.toFixed(1)},${y.toFixed(1)}) rotate(180) scale(${s.toFixed(2)})`);
    }

    for (const { el, t, s } of uses2) {
      const [x, y] = B(t, p1, p2, p3);
      const [nx, ny] = inwardNormal(t, p1, p2, p3);
      const off = L2_OFFSET_FRAC * FEATHER_LEN * s;
      el.setAttribute('transform',
        `translate(${(x + nx*off).toFixed(1)},${(y + ny*off).toFixed(1)}) rotate(180) scale(${s.toFixed(2)})`);
    }

    requestAnimationFrame(frame);
  }

  requestAnimationFrame(frame);
})();
